drop policy if exists "authenticated read own profile" on public.perfis; create policy "authenticated read own profile" on public.perfis for select to authenticated using (id=(select auth.uid()) or private.is_gestor((select auth.uid()))); comment on policy "authenticated read own profile" on public.perfis is 'Usuario autenticado le o proprio perfil; gestor le todos para administracao.';
drop policy if exists "authenticated update own profile name" on public.perfis; drop policy if exists "gestores create perfis" on public.perfis; create policy "gestores create perfis" on public.perfis for insert to authenticated with check (private.is_gestor((select auth.uid()))); comment on policy "gestores create perfis" on public.perfis is 'Somente gestor cria perfis.';
