do $$ declare t text; begin foreach t in array array['status_contrato','status_unidade','status_ordem','status_atendimento','status_pendencia','tipos_movimentacao'] loop execute format('drop policy if exists "%s_select_autenticado" on public.%I',t,t); execute format('create policy "%s_select_autenticado" on public.%I for select to authenticated using (private.has_active_profile((select auth.uid())))',t,t); execute format('comment on policy "%s_select_autenticado" on public.%I is %L',t,t,'Catalogo de dominio disponivel para usuarios ativos.'); end loop; foreach t in array array['clientes','empresas','contratos','projetos','unidades_instaladas','colaboradores','terceirizados','estoque_materiais','pendencias_padrao'] loop execute format('drop policy if exists "%s_select_autenticado" on public.%I',t,t); execute format('drop policy if exists "%s_insert_gestor" on public.%I',t,t); execute format('drop policy if exists "%s_update_gestor" on public.%I',t,t); execute format('create policy "%s_select_autenticado" on public.%I for select to authenticated using (private.has_active_profile((select auth.uid())))',t,t); execute format('create policy "%s_insert_gestor" on public.%I for insert to authenticated with check (private.is_gestor((select auth.uid())))',t,t); execute format('create policy "%s_update_gestor" on public.%I for update to authenticated using (private.is_gestor((select auth.uid()))) with check (private.is_gestor((select auth.uid())))',t,t); execute format('comment on policy "%s_select_autenticado" on public.%I is %L',t,t,'Tecnico e gestor ativos consultam cadastro base.'); execute format('comment on policy "%s_insert_gestor" on public.%I is %L',t,t,'Somente gestor cria cadastro base.'); execute format('comment on policy "%s_update_gestor" on public.%I is %L',t,t,'Somente gestor altera cadastro base e soft-delete.'); end loop; end $$;
